CREATE TABLE IF NOT EXISTS "CancellationFeedback" ("id" TEXT NOT NULL PRIMARY KEY, "motivo" TEXT NOT NULL, "detalhe" TEXT, "accepted_discount" BOOLEAN NOT NULL DEFAULT false, "accepted_downgrade" BOOLEAN NOT NULL DEFAULT false, "created_at" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, "usuario_id" TEXT NOT NULL, CONSTRAINT "CancellationFeedback_usuario_id_fkey" FOREIGN KEY ("usuario_id") REFERENCES "User" ("id") ON DELETE RESTRICT ON UPDATE CASCADE);
